clock globalTime;

const int INFINITE_TIME = -1;

const int INF = INFINITE_TIME;

const int N_REACTANTS = 12;

broadcast chan reached[N_REACTANTS];

broadcast chan reaching, do_update;

typedef struct {
	int[-99980001,99980001] b;
	int e;
} double_t;

const double_t zero = {0, 0};

const double_t INFINITE_TIME_DOUBLE = {-1000, -3};

int R2 = 100;

const int R2Levels = 100;

const double_t R2Levels_d = {1000, -1};

int R0 = 100;

const int R0Levels = 100;

const double_t R0Levels_d = {1000, -1};

int R1 = 100;

const int R1Levels = 100;

