typedef int[-1,1073741822] time_t;

typedef int[-1073741822,1073741822] int_t;

typedef struct {
	time_t T;
} timeActivity;

timeActivity R8_R7;

const double_t k_R8_R7 = {1000, -8};

timeActivity R4_R3;

const double_t k_R4_R3 = {1042, -11};

timeActivity R5_R4;

const double_t k_R5_R4 = {1000, -8};

