double_t subtract(double_t a, double_t b) {
	double_t r = {-1000, -1000};
	if(a.b == 0) {
		r.b = -b.b;
		r.e = b.e;
		return r;
	} 
	if(b.b == 0) {
		return a;
	} 
	if(a.e-b.e >= 4) {
		return a;
	} 
	if(b.e-a.e >= 4) {
		r.b = -b.b;
		r.e = b.e;
		return r;
	} 
	if(a.e == b.e) {
		r.b = a.b-b.b;
		r.e = a.e;
	} 
	if(a.e-b.e == 1) {
		r.b = a.b-b.b/10;
		r.e = a.e;
	} 
	if(a.e-b.e == 2) {
		r.b = a.b-b.b/100;
		r.e = a.e;
	} 
	if(a.e-b.e == 3) {
		r.b = a.b-b.b/1000;
		r.e = a.e;
	} 
	if(b.e-a.e == 1) {
		r.b = a.b/10-b.b;
		r.e = b.e;
	} 
	if(b.e-a.e == 2) {
		r.b = a.b/100-b.b;
		r.e = b.e;
	} 
	if(b.e-a.e == 3) {
		r.b = a.b/1000-b.b;
		r.e = b.e;
	} 
	if(r.b > 0 and r.b < 10 or r.b < 0 and r.b > -10) {
		r.b = r.b*1000;
		r.e = r.e-3;
	} 
	else 
		if(r.b > 0 and r.b < 100 or r.b < 0 and r.b > -100) {
		r.b = r.b*100;
		r.e = r.e-2;
	} 
	else 
		if(r.b > 0 and r.b < 1000 or r.b < 0 and r.b > -1000) {
		r.b = r.b*10;
		r.e = r.e-1;
	} 
	else 
		if(r.b > 9999 or r.b < -9999) {
		r.b = r.b/10;
		r.e = r.e+1;
	} 
	return r;
}

double_t add(double_t a, double_t b) {
	double_t r = {-1000, -1000};
	if(a.b == 0) {
		return b;
	} 
	if(b.b == 0) {
		return a;
	} 
	if(a.e-b.e >= 4) {
		return a;
	} 
	if(b.e-a.e >= 4) {
		return b;
	} 
	if(a.e == b.e) {
		r.b = a.b+b.b;
		r.e = a.e;
	} 
	if(a.e-b.e == 1) {
		r.b = a.b+b.b/10;
		r.e = a.e;
	} 
	if(a.e-b.e == 2) {
		r.b = a.b+b.b/100;
		r.e = a.e;
	} 
	if(a.e-b.e == 3) {
		r.b = a.b+b.b/1000;
		r.e = a.e;
	} 
	if(b.e-a.e == 1) {
		r.b = a.b/10+b.b;
		r.e = b.e;
	} 
	if(b.e-a.e == 2) {
		r.b = a.b/100+b.b;
		r.e = b.e;
	} 
	if(b.e-a.e == 3) {
		r.b = a.b/1000+b.b;
		r.e = b.e;
	} 
	if(r.b > 0 and r.b < 10 or r.b < 0 and r.b > -10) {
		r.b = r.b*1000;
		r.e = r.e-3;
	} 
	else 
		if(r.b > 0 and r.b < 100 or r.b < 0 and r.b > -100) {
		r.b = r.b*100;
		r.e = r.e-2;
	} 
	else 
		if(r.b > 0 and r.b < 1000 or r.b < 0 and r.b > -1000) {
		r.b = r.b*10;
		r.e = r.e-1;
	} 
	else 
		if(r.b > 9999 or r.b < -9999) {
		r.b = r.b/10;
		r.e = r.e+1;
	} 
	return r;
}

double_t multiply(double_t a, double_t b) {
	double_t r;
	r.b = a.b*b.b;
	if(r.b%1000 < 500) {
		r.b = r.b/1000;
	} 
	else {
		r.b = 1+r.b/1000;
	}
	r.e = a.e+b.e+3;
	if(r.b > 0 and r.b < 10 or r.b < 0 and r.b > -10) {
		r.b = r.b*1000;
		r.e = r.e-3;
	} 
	else 
		if(r.b > 0 and r.b < 100 or r.b < 0 and r.b > -100) {
		r.b = r.b*100;
		r.e = r.e-2;
	} 
	else 
		if(r.b > 0 and r.b < 1000 or r.b < 0 and r.b > -1000) {
		r.b = r.b*10;
		r.e = r.e-1;
	} 
	while(r.b > 9999 or r.b < -9999) {
		r.b = r.b/10;
		r.e = r.e+1;
	}
	return r;
}

double_t divide(double_t a, double_t b) {
	double_t r;
	if(b.b == 0) {
		return INFINITE_TIME_DOUBLE;
	} 
	r.b = a.b*1000/b.b;
	r.e = a.e-b.e-3;
	if(r.b == 0) {
		return r;
	} 
	while(r.b < 9999 and r.b > -9999) {
		r.b = r.b*10;
		r.e = r.e-1;
	}
	while(r.b > 9999 or r.b < -9999) {
		r.b = r.b/10;
		r.e = r.e+1;
	}
	return r;
}

double_t inverse(double_t a) {
	double_t r;
	if(a.b == 0) {
		return INFINITE_TIME_DOUBLE;
	} 
	if(a.e < -12) {
		r.b = 1073;
		r.e = 6;
		return r;
	} 
	r.b = 10000000/a.b;
	r.e = -7-a.e;
	if(r.b > 0 and r.b < 10 or r.b < 0 and r.b > -10) {
		r.b = r.b*1000;
		r.e = r.e-3;
	} 
	else 
		if(r.b > 0 and r.b < 100 or r.b < 0 and r.b > -100) {
		r.b = r.b*100;
		r.e = r.e-2;
	} 
	else 
		if(r.b > 0 and r.b < 1000 or r.b < 0 and r.b > -1000) {
		r.b = r.b*10;
		r.e = r.e-1;
	} 
	return r;
}

time_t power(int a, int b) {
	time_t r = 1;
	while(b > 0) {
		r = r*a;
		b = b-1;
	}
	return r;
}

int_t _ANIMO_round(double_t a) {
	if(a == INFINITE_TIME_DOUBLE) {
		return INFINITE_TIME;
	} 
	if(a.b >= 1073 and a.e >= 6) {
		return INFINITE_TIME;
	} 
	if(a.e < -4) {
		return 0;
	} 
	if(a.e == -1) {
		if(a.b%10 < 5) {
			return a.b/10;
		} 
		else {
			return 1+a.b/10;
		}
	} 
	if(a.e == -2) {
		if(a.b%100 < 50) {
			return a.b/100;
		} 
		else {
			return 1+a.b/100;
		}
	} 
	if(a.e == -3) {
		if(a.b%1000 < 500) {
			return a.b/1000;
		} 
		else {
			return 1+a.b/1000;
		}
	} 
	if(a.e == -4) {
		if(a.b < 5000) {
			return 0;
		} 
		else {
			return 1;
		}
	} 
	return a.b*power(10, a.e);
}

double_t scenario1(double_t k, double_t r1, double_t r1Levels, bool r1Active) {
	double_t E;
	if(r1Active) {
		E = r1;
	} 
	else {
		E = subtract(r1Levels, r1);
	}
	return multiply(k, E);
}

double_t scenario2_3(double_t k, double_t r2, double_t r2Levels, bool r2Active, double_t r1, double_t r1Levels, bool r1Active) {
	double_t E, S;
	if(r1Active) {
		E = r1;
	} 
	else {
		E = subtract(r1Levels, r1);
	}
	if(r2Active) {
		S = r2;
	} 
	else {
		S = subtract(r2Levels, r2);
	}
	return multiply(k, multiply(E, S));
}

double_t int_to_double(int_t a) {
	double_t r;
	bool neg = false;
	if(a < 0) {
		a = -a;
		neg = true;
	} 
	if(a < 10) {
		r.b = a*1000;
		r.e = -3;
	} 
	else 
		if(a < 100) {
		r.b = a*100;
		r.e = -2;
	} 
	else 
		if(a < 1000) {
		r.b = a*10;
		r.e = -1;
	} 
	else 
		if(a < 10000) {
		r.b = a;
		r.e = 0;
	} 
	else {
		r.e = 0;
		while(a > 9999) {
			a = a/10;
			r.e = r.e+1;
		}
		r.b = a;
	}
	if(neg) {
		r.b = -r.b;
	} 
	return r;
}

template.declaration:
int[-1,1] delta = 0;

time_t TL, TU;

clock c;

double_t totalRate = INFINITE_TIME_DOUBLE, oldRate = INFINITE_TIME_DOUBLE;

double_t compute_rate() {
	double_t R4_R3_r = scenario2_3(k_R4_R3, int_to_double(R3), int_to_double(R3Levels), false, int_to_double(R4), int_to_double(R4Levels), true);
	double_t R7_R3_r = scenario2_3(k_R7_R3, int_to_double(R3), int_to_double(R3Levels), false, int_to_double(R7), int_to_double(R7Levels), true);
	double_t R2_R3_r = scenario2_3(k_R2_R3, int_to_double(R3), int_to_double(R3Levels), true, int_to_double(R2), int_to_double(R2Levels), true);
	if(R4_R3_r.b == 0 and R4 > 0) {
		R4_R3_r = scenario2_3(k_R4_R3, int_to_double(R3Levels - 1), int_to_double(R3Levels), false, int_to_double(R4), int_to_double(R4Levels), true);
	} 
	if(R7_R3_r.b == 0 and R7 > 0) {
		R7_R3_r = scenario2_3(k_R7_R3, int_to_double(R3Levels - 1), int_to_double(R3Levels), false, int_to_double(R7), int_to_double(R7Levels), true);
	} 
	if(R2_R3_r.b == 0 and R2 > 0) {
		R2_R3_r = scenario2_3(k_R2_R3, int_to_double(1), int_to_double(R3Levels), true, int_to_double(R2), int_to_double(R2Levels), true);
	} 
	return subtract(add(add(zero, R4_R3_r), R7_R3_r), R2_R3_r);
}

void update() {
	oldRate = totalRate;
	totalRate = compute_rate();
	if(totalRate.b < 0) {
		delta = -1;
		totalRate.b = -totalRate.b;
	} 
	else {
		delta = 1;
	}
	if(totalRate.b != 0) {
		TL = _ANIMO_round(inverse(totalRate));
		TU = TL;
		if(TL < 1) {
			TL = 1;
		} 
		if(TU < 1) {
			TU = 1;
		} 
	} 
	else {
		TL = INFINITE_TIME;
		TU = INFINITE_TIME;
	}
	if(TL != INFINITE_TIME and TL > TU) {
		TL = TU;
	} 
	if(delta >= 0 and R == MAX or delta < 0 and R == 0) {
		TL = TU = INFINITE_TIME;
	} 
}

void reach() {
	if(-MAX <= R+delta and R+delta <= MAX) {
		R = R+delta;
	} 
}

void make_urgent() {
	c = 0;
	TU = 0;
	TL = 0;
}

bool rate_significantly_changed(double_t oldRate, double_t newRate) {
	if((oldRate.b < 0 and newRate.b > 0 or oldRate.b > 0 and newRate.b < 0) and R < MAX and R > 0) {
		return true;
	} 
	return false;
}

void decide_reset() {
	if(rate_significantly_changed(oldRate, totalRate)) {
		c = 0;
	} 
}

bool infinite_delay() {
	return TU == INFINITE_TIME;
}

